changeSet.sql:
UPDATE request_task SET payload = jsonb_set( payload, '{emissionsMonitoringPlan, emissions, ships}', ( SELECT jsonb_agg( jsonb_set( ship, '{emissionsSources}', ( SELECT jsonb_agg( CASE WHEN (esm->>'methaneSlip') IN ('0', '0.2', '1.7', '2.6', '3.1') THEN jsonb_set(esm, '{methaneSlipValueType}', '"PRESELECTED"') ELSE jsonb_set(esm, '{methaneSlipValueType}', '"OTHER"') END ) FROM jsonb_array_elements(ship->'emissionsSources') AS esm ) ) ) FROM jsonb_array_elements(payload->'emissionsMonitoringPlan'->'emissions'->'ships') AS ship ) )
WHERE payload ?? 'emissionsMonitoringPlan' AND payload->'emissionsMonitoringPlan' ?? 'emissions' AND payload->'emissionsMonitoringPlan'->'emissions' ?? 'ships' AND jsonb_array_length(payload->'emissionsMonitoringPlan'->'emissions'->'ships') > 0 AND payload->>'payloadType' IN ( 'EMP_ISSUANCE_APPLICATION_SUBMIT_PAYLOAD', 'EMP_ISSUANCE_WAIT_FOR_REVIEW_PAYLOAD', 'EMP_ISSUANCE_APPLICATION_REVIEW_PAYLOAD', 'EMP_ISSUANCE_APPLICATION_PEER_REVIEW_PAYLOAD', 'EMP_ISSUANCE_WAIT_FOR_PEER_REVIEW_PAYLOAD', 'EMP_ISSUANCE_APPLICATION_AMENDS_SUBMIT_PAYLOAD', 'EMP_ISSUANCE_WAIT_FOR_AMENDS_PAYLOAD',
'EMP_VARIATION_APPLICATION_SUBMIT_PAYLOAD', 'EMP_VARIATION_APPLICATION_REVIEW_PAYLOAD', 'EMP_VARIATION_WAIT_FOR_REVIEW_PAYLOAD', 'EMP_VARIATION_APPLICATION_SUBMIT_REGULATOR_LED_PAYLOAD', 'EMP_VARIATION_APPLICATION_PEER_REVIEW_PAYLOAD', 'EMP_VARIATION_APPLICATION_WAIT_FOR_PEER_REVIEW_PAYLOAD', 'EMP_VARIATION_APPLICATION_PEER_REVIEW_REGULATOR_LED_PAYLOAD', 'EMP_VARIATION_WAIT_FOR_PEER_REVIEW_REGULATOR_LED_PAYLOAD', 'EMP_VARIATION_APPLICATION_AMENDS_SUBMIT_PAYLOAD', 'EMP_VARIATION_WAIT_FOR_AMENDS_PAYLOAD' );

UPDATE request_action SET payload = jsonb_set( payload, '{emissionsMonitoringPlan, emissions, ships}', ( SELECT jsonb_agg( jsonb_set( ship, '{emissionsSources}', ( SELECT jsonb_agg( CASE WHEN (esm->>'methaneSlip') IN ('0', '0.2', '1.7', '2.6', '3.1') THEN jsonb_set(esm, '{methaneSlipValueType}', '"PRESELECTED"') ELSE jsonb_set(esm, '{methaneSlipValueType}', '"OTHER"') END ) FROM jsonb_array_elements(ship->'emissionsSources') AS esm ) ) ) FROM jsonb_array_elements(payload->'emissionsMonitoringPlan'->'emissions'->'ships') AS ship ) )
WHERE payload ?? 'emissionsMonitoringPlan' AND payload->'emissionsMonitoringPlan' ?? 'emissions' AND payload->'emissionsMonitoringPlan'->'emissions' ?? 'ships' AND jsonb_array_length(payload->'emissionsMonitoringPlan'->'emissions'->'ships') > 0 AND payload->>'payloadType' IN ( 'EMP_ISSUANCE_APPLICATION_SUBMITTED_PAYLOAD', 'EMP_ISSUANCE_APPLICATION_APPROVED_PAYLOAD', 'EMP_ISSUANCE_APPLICATION_AMENDS_SUBMITTED_PAYLOAD',
'EMP_VARIATION_APPLICATION_SUBMITTED_PAYLOAD', 'EMP_VARIATION_APPLICATION_REGULATOR_LED_APPROVED_PAYLOAD', 'EMP_VARIATION_APPLICATION_REJECTED_PAYLOAD', 'EMP_VARIATION_APPLICATION_AMENDS_SUBMITTED_PAYLOAD', 'EMP_VARIATION_APPLICATION_APPROVED_PAYLOAD' );
